import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.BGHOrOyn.js";const s="/gitbook-personnal-docs/assets/image%20(20).DjYAC1HO.",n="/gitbook-personnal-docs/assets/image%20(21).BRg_AI1h.",r="/gitbook-personnal-docs/assets/image%20(22).DqzRH2AX.",c="/gitbook-personnal-docs/assets/image%20(23).ClhWbWEb.",d="/gitbook-personnal-docs/assets/image%20(24).DU792q2r.",l="/gitbook-personnal-docs/assets/image%20(25).IEIDk42f.",p="/gitbook-personnal-docs/assets/image%20(26).O3X9eC7G.",m="/gitbook-personnal-docs/assets/image%20(27).DtUL6J3J.",h="/gitbook-personnal-docs/assets/image%20(28).fTPjZzBH.",u="/gitbook-personnal-docs/assets/image%20(29).CBjRN6Mg.",g="/gitbook-personnal-docs/assets/image%20(30).BUBZ8ZnZ.",f="/gitbook-personnal-docs/assets/image%20(31).D_BzlHkd.",b="/gitbook-personnal-docs/assets/image%20(32).CNIudnGk.",C=JSON.parse('{"title":"Using ChatGPT to build System Diagrams — Part I","description":"","frontmatter":{},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/using-chatgpt-to-build-system-diagrams-part-i.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/using-chatgpt-to-build-system-diagrams-part-i.md"}'),w={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/using-chatgpt-to-build-system-diagrams-part-i.md"};function y(k,e,_,v,T,P){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="using-chatgpt-to-build-system-diagrams-—-part-i" tabindex="-1">Using ChatGPT to build System Diagrams — Part I <a class="header-anchor" href="#using-chatgpt-to-build-system-diagrams-—-part-i" aria-label="Permalink to &quot;Using ChatGPT to build System Diagrams — Part I&quot;">​</a></h1><p>Interested in Mindmaps — read our blog post on using plantUML with ChatGPT to create awesome Mindmaps: <a href="https://link.medium.com/q5YglIQ74wb" target="_blank" rel="noreferrer">https://link.medium.com/q5YglIQ74wb</a></p><p>The popularity of ChatGPT keeps growing and it’s now being used in a wide range of applications. As a software architect, I had the opportunity to explore ChatGPT’s capabilities for use within the financial domain, specifically for Wealth Management.</p><p><img src="'+s+'" alt=""></p><p>Photo by <a href="https://unsplash.com/@wocintechchat?utm_source=medium&amp;utm_medium=referral" target="_blank" rel="noreferrer">Christina @ wocintechchat.comarrow-up-right</a> on <a href="https://unsplash.com/?utm_source=medium&amp;utm_medium=referral" target="_blank" rel="noreferrer">Unsplasharrow-up-right</a></p><p>I wanted to confirm if ChatGPT could generate diagrams for a use case explanation and analyze multiple factors at the same time.</p><p>So, I logged into <a href="http://chat.openai.com/" target="_blank" rel="noreferrer">http://chat.openai.com/</a> and here is my conversation.</p><h2 id="step-1-let-s-define-the-use-case" tabindex="-1">Step 1: Let’s define the use-case <a class="header-anchor" href="#step-1-let-s-define-the-use-case" aria-label="Permalink to &quot;Step 1: Let’s define the use-case&quot;">​</a></h2><p>I could have defined my own use-case, but I wanted to test all aspects of ChatGPT, so I asked it to define one for me.</p><p><img src="'+n+'" alt=""></p><p>Use case definition</p><h3 id="step-2-let-s-define-a-data-model-for-the-use-case" tabindex="-1">Step 2: Let’s define a Data Model for the use-case <a class="header-anchor" href="#step-2-let-s-define-a-data-model-for-the-use-case" aria-label="Permalink to &quot;Step 2: Let’s define a Data Model for the use-case&quot;">​</a></h3><p>Looks good to me, let’s start by defining the data model — so I asked ChatGPT to do it and this is what I got:</p><p><img src="'+r+'" alt=""></p><p>data model definition</p><p>That sounds about right, let&#39;s see what it can do for diagrams. I wanted to drill a bit deeper on the data model so my next prompt was:</p><p>Prompt: <code>describe the data model in more detail or tabular format using markdown</code><br> ChatGPT: I can describe the structure of the data model in a tabular format using markdown.</p><p><img src="'+c+'" alt=""></p><p>data structure</p><h3 id="step-3-let-s-define-relationships-—-entity-relationship-diagram" tabindex="-1">Step 3: Let’s define relationships — Entity Relationship Diagram <a class="header-anchor" href="#step-3-let-s-define-relationships-—-entity-relationship-diagram" aria-label="Permalink to &quot;Step 3: Let’s define relationships — Entity Relationship Diagram&quot;">​</a></h3><p>Prompt: this is perfect, I would like to depict the relationships in a mermaid diagram, can you give me the markdown code to do this<br> ChatGPT: I apologize, but as a text-based model, I am not able to generate Mermaid diagrams or any other visual diagrams. However, I can provide you with an example of how the relationships could be represented in Mermaid syntax:</p><p><img src="'+d+'" alt=""></p><p>mermaid syntax for data relationships</p><p>And copying this in a markdown editor enclosed within {mermaid} tags, I got:</p><p><img src="'+l+'" alt=""></p><p>data model in mermaid</p><h3 id="step-4-sequence-diagram" tabindex="-1">Step 4: Sequence Diagram <a class="header-anchor" href="#step-4-sequence-diagram" aria-label="Permalink to &quot;Step 4: Sequence Diagram&quot;">​</a></h3><p>Next, I tried to make hypothetical prompts to check responses. My first intention was to get a sequence diagram created.</p><p>Prompt: how would a Buy transaction for an asset impact the tables mentioned above, I would like to depict this as a sequence diagram. Can you help describe the diagram in markdown format for mermaid<br> ChatGPT: Sure, a <code>Buy</code> transaction would have an impact on the following tables:</p><ul><li><code>Asset</code> table: the <code>current_value</code> of the asset would be updated to reflect the current market value of the asset</li><li><code>Portfolio</code> table: the <code>current_value</code> of the portfolio would be updated to reflect the new asset and its market value, and the <code>asset_allocation</code> would be updated to reflect the new asset.</li><li><code>Transaction</code> table: a new transaction would be added with the transaction details such as the transaction type, transaction date, asset_id, and portfolio_id</li></ul><p>Here is an example of how the process could be represented in a Mermaid sequence diagram:</p><p><img src="'+p+'" alt=""></p><p>sequence diagram for a buy transaction</p><p>and copying this is in a markdown editor:</p><p><img src="'+m+'" alt=""></p><p>sequence diagram</p><h3 id="step-5-state-transition-diagram" tabindex="-1">Step 5: State Transition Diagram <a class="header-anchor" href="#step-5-state-transition-diagram" aria-label="Permalink to &quot;Step 5: State Transition Diagram&quot;">​</a></h3><p>Let me ask about a <code>State Transition</code> diagram.</p><p>Prompt: Will the account have states like new, closed, active inactive etc? I would like to depict the states in a state diagram using mermaid. Can you help describe the diagram in markdown format<br> ChatGPT: It is common for financial accounts to have different states, such as new, closed, active, and inactive, to reflect the current status of the account.</p><ul><li><code>new</code> account would be one that has just been opened and is awaiting funding or verification.</li><li><code>active</code> account would be one that is currently open and being used for transactions.</li><li><code>inactive</code> account would be one that is not currently being used but has not been closed.</li><li><code>closed</code> account would be one that has been closed by the customer or the financial institution, and no longer able to be used for transactions.</li><li><code>Pending</code> state could be used to indicate that the account is under review or awaiting verification.</li><li><code>Suspended</code> state could be used to indicate that the account has been temporarily suspended, for example, due to suspicious activity or non-compliance with terms and conditions.</li><li><code>Frozen</code> state could be used to indicate that the account has been frozen, for example, due to a legal dispute or regulatory action.</li><li><code>Expired</code> state could be used to indicate that the account has reached its expiration date and is no longer in use.</li></ul><p>Here is an example of how the states of an account could be represented in a Mermaid state diagram:</p><p><img src="'+h+'" alt=""></p><p>Sequence Diagram (state diagram image)</p><p>Looks like this format is older and may break due to cyclical dependencies. So I asked ChatGPT to improve this.</p><p>Prompt: can you try giving the state diagram markdown syntax in new format using <code>[*]</code><br> ChatGPT: Sure, here is an example of how a state diagram for a wealth management system&#39;s account management component could be represented in Mermaid using the new format with <code>[*]</code>:</p><p><img src="'+u+'" alt=""></p><p>mermaid representation of state diagram</p><p>Markdown Editor Representation:</p><p><img src="'+g+'" alt=""></p><p>This diagram shows the different states of an account and the possible transitions between them.</p><ul><li>The initial state is <code>[*]</code> which denotes the start state.</li><li>The account can transition from <code>New</code> state to <code>Active</code> state by activating it.</li><li>The account can transition from <code>New</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Active</code> state to <code>Inactive</code> state by deactivating it.</li><li>The account can transition from <code>Active</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Inactive</code> state to <code>Active</code> state by activating it.</li><li>The account can transition from <code>Inactive</code> state to <code>Closed</code> state by closing it.</li></ul><p>Now we are getting somewhere. Let’s extend this further to include other states as well.</p><p>Prompt: please include expired, frozen and other relevant states as well<br> ChatGPT: Sure, here is an example of how a state diagram for a wealth management system’s account management component could be represented in Mermaid including additional states such as <code>Expired</code>, <code>Frozen</code>, etc:</p><p>Description:<br> This diagram shows the different states of an account and the possible transitions between them.</p><ul><li>The initial state is <code>[*]</code> which denotes the start state.</li><li>The account can transition from <code>New</code> state to <code>Active</code> state by activating it.</li><li>The account can transition from <code>New</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Active</code> state to <code>Inactive</code> state by deactivating it.</li><li>The account can transition from <code>Active</code> state to <code>Frozen</code> state by freezing it.</li><li>The account can transition from <code>Active</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Inactive</code> state to <code>Active</code> state by activating it.</li><li>The account can transition from <code>Inactive</code> state to <code>Frozen</code> state by freezing it.</li><li>The account can transition from <code>Inactive</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Frozen</code> state to <code>Active</code> state by unfreezing it.</li><li>The account can transition from <code>Frozen</code> state to <code>Closed</code> state by closing it.</li><li>The account can transition from <code>Closed</code> state to <code>Expired</code> state if the account is expired.</li></ul><p><img src="'+f+'" alt=""></p><p>extended state diagram</p><p>Diagrammatic Representation:</p><p><img src="'+b+'" alt=""></p><p>This is awesome. Truly impressive on what can be achieved with ChatGPT and Mermaid</p><p>I next moved on to describing and building more diagrams using the C4 model and will add them to a follow up post: <a href="https://medium.com/@aruva/using-chatgpt-to-build-system-diagrams-part-ii-a17d02f0dcb7" target="_blank" rel="noreferrer">https://medium.com/@aruva/using-chatgpt-to-build-system-diagrams-part-ii-a17d02f0dcb7</a></p><p>Thanks for reading!</p><p>Please subscribe here to never miss our new posts and don’t forget to clap if you enjoyed reading this post: <a href="https://aruva.medium.com/membership" target="_blank" rel="noreferrer">https://aruva.medium.com/membership</a></p>',63)])])}const x=t(w,[["render",y]]);export{C as __pageData,x as default};
